"use client";

import Image from "next/image";
import { motion, AnimatePresence } from "framer-motion";
import { FaFacebookF, FaInstagram, FaLinkedinIn } from "react-icons/fa";

export default function TeamCard({ member, isActive, onHover }) {
  return (
    <div
      onMouseEnter={onHover}
      className="relative h-[420px] rounded-3xl overflow-hidden border border-fuchsia-500/50 cursor-pointer group"
    >
      {/* Image with brightness control */}
      <Image
        src={member.image}
        alt={member.name}
        fill
        className={`object-cover object-top transition duration-500 
        ${isActive ? "brightness-75" : "brightness-95 group-hover:brightness-75"}`}
      />

      {/* Bottom Blue Line Detail */}
      <div className="absolute bottom-0 left-0 w-full h-[3px] bg-[#2b4dff]" />

      {/* Name + Role Bottom Sliding Box */}
      <AnimatePresence>
        {isActive && (
          <motion.div
            initial={{ y: 80, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: 80, opacity: 0 }}
            transition={{ duration: 0.4 }}
            className="absolute bottom-0 left-0 w-full bg-[#2b4dff] text-white px-6 py-5 z-10"
          >
            <h3 className="text-lg font-semibold">
              {member.name}
            </h3>
            <p className="text-sm opacity-90">
              {member.role}
            </p>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Social Pill */}
      <AnimatePresence>
        {isActive && (
          <motion.div
            initial={{ x: 40, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            exit={{ x: 40, opacity: 0 }}
            transition={{ duration: 0.4 }}
            className="absolute top-6 right-0 z-20"
          >
            <div className="bg-white rounded-l-full py-4 px-3 flex flex-col gap-4 shadow-lg">
              <a href={member.social.facebook} className="text-[#2b4dff]">
                <FaFacebookF />
              </a>
              <a href={member.social.instagram} className="text-[#2b4dff]">
                <FaInstagram />
              </a>
              <a href={member.social.linkedin} className="text-[#2b4dff]">
                <FaLinkedinIn />
              </a>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}